"use strict";(self.webpackChunkdst_api_webdocs=self.webpackChunkdst_api_webdocs||[]).push([[380277],{418732:e=>{e.exports=JSON.parse('{"tag":{"label":"follower","permalink":"/dst-api-webdocs/docs/tags/follower","allTagsPath":"/dst-api-webdocs/docs/tags","count":21,"items":[{"id":"game-scripts/prefabs/armor_carrotlure","title":"Armor Carrotlure","description":"An equippable armor item that periodically attracts and extends loyalty of rabbit followers within range of its owner, who must be a leader.","permalink":"/dst-api-webdocs/docs/game-scripts/prefabs/armor_carrotlure"},{"id":"game-scripts/brains/braincommon","title":"Braincommon","description":"Provides shared AI behavior utilities for followers and non-player entities, including panic triggers, saltlick navigation, and leader-assisted actions.","permalink":"/dst-api-webdocs/docs/game-scripts/brains/braincommon"},{"id":"game-scripts/prefabs/bunnyman","title":"Bunnyman","description":"A sentient pig-like creature that can follow players, wear hats, and enter a powerful \\"beard lord\\" nightmare state under certain conditions.","permalink":"/dst-api-webdocs/docs/game-scripts/prefabs/bunnyman"},{"id":"game-scripts/prefabs/catcoon","title":"Catcoon","description":"Implements the catcoon creature, a tameable animal that interacts with players through trading, retching gifts, and combat with flocking behavior.","permalink":"/dst-api-webdocs/docs/game-scripts/prefabs/catcoon"},{"id":"game-scripts/components/follower_replica","title":"Follower Replica","description":"Manages networked references to an entity\'s leader or item owner for follower behavior synchronization between client and server.","permalink":"/dst-api-webdocs/docs/game-scripts/components/follower_replica"},{"id":"game-scripts/components/followerherder","title":"Followerherder","description":"Manages herd behavior for a leader entity, toggling hostile state of all followers and consuming finite uses when triggered.","permalink":"/dst-api-webdocs/docs/game-scripts/components/followerherder"},{"id":"game-scripts/prefabs/fruitfly","title":"Fruitfly","description":"Manages fruit fly entities with distinct behaviors for hostile lord/mini variants, friendly companions, and seed-bearing fruit fly fruit that spawn companions.","permalink":"/dst-api-webdocs/docs/game-scripts/prefabs/fruitfly"},{"id":"game-scripts/prefabs/gestalt_head","title":"Gestalt Head","description":"Creates a non-networked, follower-based visual FX entity for the Gestalt and Gestalt Guard characters, playing different idle animations based on the provided anim bank.","permalink":"/dst-api-webdocs/docs/game-scripts/prefabs/gestalt_head"},{"id":"game-scripts/brains/glommerbrain","title":"Glommerbrain","description":"Controls the AI behavior for Glommer, an entity that follows its leader while avoiding danger and wandering within proximity limits.","permalink":"/dst-api-webdocs/docs/game-scripts/brains/glommerbrain"},{"id":"game-scripts/prefabs/gnarwail","title":"Gnarwail","description":"Controls the behavior, state management, and interaction logic for the Gnarwail entity, including horn combat, loyalty mechanics, and formation following behavior.","permalink":"/dst-api-webdocs/docs/game-scripts/prefabs/gnarwail"},{"id":"game-scripts/prefabs/horn","title":"Horn","description":"A consumable instrument that\u53ec\u96c6s beefalo followers and tends farm plants when used by the player.","permalink":"/dst-api-webdocs/docs/game-scripts/prefabs/horn"},{"id":"game-scripts/prefabs/kitcoon","title":"Kitcoon","description":"Manages the behavior and state of kitcoons, including sleeping, following, hiding, and interacting with players and environments.","permalink":"/dst-api-webdocs/docs/game-scripts/prefabs/kitcoon"},{"id":"game-scripts/prefabs/onemanband","title":"Onemanband","description":"Manages the One Man Band inventory item, which attracts followers, enhances dapperness, and supports haunt mechanics in DST.","permalink":"/dst-api-webdocs/docs/game-scripts/prefabs/onemanband"},{"id":"game-scripts/components/repellent","title":"Repellent","description":"Causes nearby entities with specified repel tags to stop following their leader or drop combat targets when activated.","permalink":"/dst-api-webdocs/docs/game-scripts/components/repellent"},{"id":"game-scripts/prefabs/rocky","title":"Rocky","description":"Manages Rocky\'s behavior as a controllable NPC character, including growth mechanics, follower loyalty, combat targeting, and interaction with players via trading.","permalink":"/dst-api-webdocs/docs/game-scripts/prefabs/rocky"},{"id":"game-scripts/stategraphs/SGticoon","title":"Sgticoon","description":"Defines the state graph for the Ticoon entity, governing its AI behavior including idle, walking, searching for a quest target, waiting for its leader, and reacting to events such as abandonment or finding a kitcoon.","permalink":"/dst-api-webdocs/docs/game-scripts/stategraphs/SGticoon"},{"id":"game-scripts/prefabs/smallbird","title":"Smallbird","description":"Manages the lifecycle, behavior, and growth progression of small birds (including their teenage and adult tallbird forms) as companions with combat, eating, sleeping, and follower mechanics.","permalink":"/dst-api-webdocs/docs/game-scripts/prefabs/smallbird"},{"id":"game-scripts/brains/smallbirdbrain","title":"Smallbirdbrain","description":"Controls the AI behavior of small birds, prioritizing survival (starvation, food), following leaders, evading players when not companions, and engaging in combat when necessary.","permalink":"/dst-api-webdocs/docs/game-scripts/brains/smallbirdbrain"},{"id":"game-scripts/prefabs/spiderqueen","title":"Spiderqueen","description":"A boss-level spider entity that commands a hive of followers, generates eggs and spiders, and uses shared aggro mechanics to coordinate attacks with nearby spiders.","permalink":"/dst-api-webdocs/docs/game-scripts/prefabs/spiderqueen"},{"id":"game-scripts/prefabs/ticoon","title":"Ticoon","description":"A companion entity that tracks and retrieves hidden Kitcoons for a player leader, with combat and quest management capabilities.","permalink":"/dst-api-webdocs/docs/game-scripts/prefabs/ticoon"},{"id":"game-scripts/brains/wormwood_carratbrain","title":"Wormwood Carratbrain","description":"AI behavior tree controller that governs Carrat movement and interaction with the environment and leader in Don\'t Starve Together.","permalink":"/dst-api-webdocs/docs/game-scripts/brains/wormwood_carratbrain"}],"unlisted":false}}')}}]);